examples.fromCode:
interface User {
  id: number;
  email: string;
  isActive: boolean;
}

function activateUser(user: User): User {
  return { ...user, isActive: true };
}

examples.toCode:
from dataclasses import dataclass

@dataclass
class User:
    id: int
    email: str
    is_active: bool

def activate_user(user: User) -> User:
    user.is_active = True
    return user

